var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"어떻게 된 거야, 이 늙은이? 끌고 오는 내내 반항 한 번 안 하네.","JPN":"どうしたんだ、この老いぼれ。ここまで来る途中、一度も抵抗しなかったぞ。","ENG":"What's with this old hag? She hasn't resisted once the whole time we dragged her here.","TWN":"那個老太婆怎麼回事？這一路上竟然沒有一絲反抗。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"사람 죽는 꼴을 보고 정신이 나간 거겠지.","JPN":"人が死ぬ様を見て気が抜けたんだろ？","ENG":"She's just out of it after seeing people die in front of her.","TWN":"可能是看到那麼多人慘死被嚇到吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"아니면 살기를 포기했거나.","JPN":"生きることを諦めたとか。","ENG":"That, or she's given up on life.","TWN":"或是已經失去求生意志。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"내버려 둬. 그 나이에 살겠다고 발버둥치는 것도 꼴사나워.","JPN":"放っておけ。その年で生きようと足掻く程醜いこともない。","ENG":"Leave her be. It's unsightly for someone that old to keep struggling to stay alive, anyway.","TWN":"別管她，都活到這把年紀還在乎活命豈不是很難看。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"교전에 투입한 융합체들의 신호는 잡히고 있어?","JPN":"交戦に投入した融合体たちの信号は？","ENG":"Are you getting a signal for the hybriders we deployed to battle?","TWN":"有掌握到投入戰場的融合體訊號嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그게……. 저희가 기지에 도착했을 때는 전부 두절된 이후였습니다.","JPN":"それが……我々が基地に着いた時には、すでにすべて途絶えていました。","ENG":"Well... by the time we arrived, their signals had already been disconnected.","TWN":"這個……在我們抵達基地後就完全失去訊號。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그래?","JPN":"ほう？","ENG":"Really?","TWN":"是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"의외의 결과네. 이번에 투입한 융합체들은 하이드리히 경의 개량형이었잖아?","JPN":"意外な結果だな。今回投入した融合体はすべて、ハイドリヒ卿の改良型だっただろう？","ENG":"That's unexpected. But wasn't this group of hybriders modified by Sir Heydrich?","TWN":"出乎我意料，這次投入的融合體可是海德里希的改良型呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"걱정 마십시오. 지금 교전 데이터를 수집 중입니다.","JPN":"ご心配には及びません。今、交戦データを収集中です。","ENG":"Don't worry, sir. Their battle data is being collected now.","TWN":"不要擔心，目前正在收集交戰資料。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"하이드리히 경 덕분에 융합체 개량은 새로운 국면을 맞이했습니다.","JPN":"ハイドリヒ卿のおかげで、融合体の改良は新局面を迎えました。","ENG":"Thanks to Sir Heydrich, we entered a new era of hybrider modification.","TWN":"拜海德里希所賜，融合體的改良才能有新的突破。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"시간과 예산만 더 주어진다면…. 어쩌면 카운터를 능가할 수 있을지도…….","JPN":"時間と予算の余裕さえあれば……もしかすると、カウンターを越えることができるかも……","ENG":"With more budget and time... they might even surpass Counters...","TWN":"如果有充分的時間和預算，甚至有可能超越制裁者……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"시간과 예산은 항상 부족했어. 앞으로도 그럴 테고.","JPN":"時間と予算はいつもギリギリだった。この先もそれは変わらないだろう。","ENG":"We were always short on both funds and time. And that will not change anytime soon.","TWN":"時間和預算不可能充分，以後也一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그래서 저 늙은이가 필요한 거야. 활용하기에 따라선 그로니아와 북방합의체 양측의 지원을 요구할 수 있을 테니까.","JPN":"だからあの老いぼれが必要なんだ。使い方によっては、グロニアと北方合意体、両方からの援助を要求できるはずだからな。","ENG":"That's why we need that old woman. If we use our cards right, we'll be able to ask for resources from both Gronia and the Northern Union.","TWN":"所以我們才需要那老太婆。我們可以利用她來向格羅尼亞和北方和議會要求支援。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그건…. 다른 간부 분들과 논의하지 않으셔도 되겠습니까?","JPN":"それは……他の幹部の方々と議論しなくてもいいのですか？","ENG":"Do you... not need to discuss that with the other officials first?","TWN":"這……真的不用和其他幹部討論嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"말씀을 들을수록 저희 선에서 단독으로 추진하기엔 위험이 커 보입니다.","JPN":"話を聞けば聞くほど、我々の線で単独的に仕事を進めるにはあまりにも危険かと思われますが。","ENG":"The more I hear about it, the more I think that it will be risky for us to carry this out on our own.","TWN":"越聽你的話就越覺得，我們如果獨斷實行這個方案，會有很大的風險。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 겁먹지 마.","JPN":"はは、怖がるなよ。","ENG":"Haha, don't be so worried.","TWN":"哈哈，不用怕。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"장부는 과단성을 발휘해야 할 때가 있어. 관리국이 자멸할 때까지 소인배처럼 웅크리고 있자는 건가?","JPN":"漢は果敢に行動しなければならない時があるんだ。管理局が自滅するまで、臆病者みたいに縮こまっていろとでも言うのか？","ENG":"There are times when a man must be decisive. Or do you want to crawl and hide like a worm until the Administration implodes?","TWN":"大丈夫有時候必須當機立斷。難道要像一個膽小鬼一樣等待管理局自取滅亡嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그건 아닙니다만….","JPN":"そうではありませんが……","ENG":"Not at all, but...","TWN":"我不是這個意思…"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"자, 지금은 우리를 습격했던 자들이 오기 전에 이 시설을 벗어나는 것이 우선이야.","JPN":"今は僕たちを襲撃したやつらが来る前に、この施設から抜け出るのが先決だ。","ENG":"Okay, then right now, our utmost priority is to flee this facility before those ambushers catch up to us.","TWN":"就這樣，現在的當務之急是在追兵來到前，趕快離開這個設施。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"저 늙은이를 데리고 주둔지에 가면 다른 간부들도 가만히 있을 수는 없겠지.","JPN":"あの老いぼれを連れて駐屯地に戻れば、他の幹部も黙ってはいられないだろう。","ENG":"Once we bring her back to base, the other officials will have to follow our plans.","TWN":"如果帶著那老太婆去基地，其他幹部一定也會有所行動。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"컥…! ……!","JPN":"かはっ……！　……！","ENG":"Kuh...! ...!","TWN":"咳…！……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"허억……! 억……!","JPN":"はあ……！　くっ……！","ENG":"Gaah...! Ugh...!","TWN":"嚇呃……！呃……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"괴, 괴물……","JPN":"ば、化け物……","ENG":"M-monster...","TWN":"怪…怪物……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님의 예상대로네.","JPN":"マエストロの予想どおりだわ。","ENG":"It's just as the Chief Conductor predicted.","TWN":"果然如指揮家所料。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"카르멘, 그 교활한 게 아무 이유 없이 나섰을 리 없지.","JPN":"カルメン、あのこざかしい子が何の理由もなく動くわけないのよ。","ENG":"That sly vixen Carmen wouldn't have volunteered to go without good reason.","TWN":"卡門那個狡猾的女人果然不會無緣無故出面。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"너는…. 제프티의?","JPN":"お前は……ジェフティの？","ENG":"You're... Jehuty's...?","TWN":"你是……傑夫堤的？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"떠돌이 악사야, 인간.","JPN":"さすらいの演奏者って呼んでね、人間。","ENG":"I'm just a wandering troubadour, human.","TWN":"我是浪人演奏家，人類。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"잘 부탁해. 오래 보진 못하겠지만?","JPN":"よろしく。長くは付き合えないでしょうけど。","ENG":"Pleasure to meet you, although we won't be seeing each other for long.","TWN":"請多關照，雖然我們可能不會相處太久。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"겨, 경비병! 침입자다! 어서 격리 구역으로 집결해!","JPN":"け、警備兵！　侵入者だ！　早く隔離区域に集結しろ！","ENG":"G-guards! An intruder! Gather the men to the quarantine sector!","TWN":"警…警衛！發現入侵者！立刻到隔離區集合！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"이거 놀라운걸. 외부인에게는 출입이 허락되지 않는 곳인데, 잘도 기어 들어왔네.","JPN":"これは驚いた。外部からの出入りを遮断している場所なのに、よく入ってこれたな。","ENG":"Isn't this a nice surprise? This place doesn't allow outsiders in, but you somehow managed to crawl your way in here.","TWN":"真令人意外，這裡禁止外部人員出入，不知道你是怎麼溜進來的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"혹시 우릴 습격했던 자들과 한 패인가?","JPN":"もしかして、僕たちを襲撃したやつらとグルなのか？","ENG":"Are you with the others who ambushed us?","TWN":"你和襲擊我們的那幫人是一夥嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐응. 아마 아닐걸.","JPN":"ふうん。たぶん違うと思うわ。","ENG":"Hmm? I don't think so.","TWN":"呵呵，應該不是吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 그 녀석들과 목적은 같을 거야.","JPN":"でも、目的は同じでしょうね。","ENG":"However, I do think that my goal aligns with theirs.","TWN":"但我的目標可能和他們一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"여기 있는 늙은 인간을 데리러 왔어. 성가신 짐을 치워 주려는 거니까 사양하지 않아도 돼.","JPN":"ここにいる老婆を連れて帰るために来たの。お荷物が片付いて助かるでしょう。遠慮しなくてもいいわよ。","ENG":"I'm here to get that old woman. You don't have to decline, since I'm doing you a favor by taking away your troublesome burden.","TWN":"我要帶走那老太婆，我是在幫你們除掉燙手山芋，不必道謝。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그렇다면 얘기는 간단해지겠군.","JPN":"それなら、話は簡単だな。","ENG":"Well, then that makes things simpler.","TWN":"既然如此，事情就很簡單了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"한 시라도 빨리 널 죽이고 그 늙은이를 데려가는 거야. 어때?","JPN":"一刻も早くお前を殺して、あの老いぼれを連れて行くんだ。どうだ？","ENG":"I'll gonna kill you and take her with me. How's that sound?","TWN":"我現在殺了你，再帶走那個老太婆。怎麼樣？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 체면이 말이 아니네. 인간 따위가 죽이네 살리네 운운하다니.","JPN":"ふふっ。見くびられたものね。人間の分際で生かす殺すを云々するなんて。","ENG":"Heh, guess I'm not what I used to be. A mere mortal threatening to kill me.","TWN":"呵呵，區區一個人類也敢說要殺我，真沒面子。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 연주를 시작해 볼까. 루나, 준비해.","JPN":"それでは演奏を始めましょうか。ルナ、準備しなさい。","ENG":"Then, shall I start my performance? Luna, get ready.","TWN":"那就開始演奏吧。露娜準備！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 알겠어!","JPN":"わ、わかった！","ENG":"O-okay!","TWN":"喔，沒問題！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그렇지만 나랑 듀엣이라니…. 정말 그래도 괜찮아?","JPN":"でもアタシとデュエットって……本当にそれで大丈夫？","ENG":"But a duet with me...? Are you sure about this?","TWN":"不過和我一起演奏二重奏……真的沒關係嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여기는 좁아서 마음껏 날기도 어려운데…….","JPN":"ここは狭くて思いっきり飛ぶこともできないのに……","ENG":"This place is so cramped that I can't even fly...","TWN":"而且這裡空間太窄，飛起來可能有些綁手綁腳……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"헛소리 하지 말아 줄래? 그럼 왜 널 데려왔다고 생각해?","JPN":"くだらないこと言ってないで。どうしてあなたを連れてきたと思ってるの？","ENG":"Please stop your nonsense. Why else would I bring you with me then?","TWN":"能別廢話嗎？不然我為什麼要帶你過來？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"읏……. 미, 미안.","JPN":"うっ……ご、ごめん。","ENG":"Ngh... S-sorry.","TWN":"呃……抱…抱歉。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관중들 앞에서 미덥지 못하게 굴면 안 되지, 얼간아.","JPN":"観客の前で頼りない姿を見せるんじゃないわよ、まぬけ。","ENG":"Stop making a fool of yourself in front of the audience, you nimwit.","TWN":"在觀眾面前可不能顯得這麼不專業，笨蛋。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"얌전히 따라오기나 해. 내가 이끄는 리듬대로.","JPN":"私が導くリズムに大人しくついてきなさい。","ENG":"Keep quiet and follow my lead into the rhythm.","TWN":"乖乖跟著我的節奏。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};